package testutils

import (
	"bufio"
	"os"
	"path/filepath"
	"sync"
	"testing"
)

func TestNewFixtureRepoCachesEachProfileOnce(t *testing.T) {
	t.Setenv("DDX_BIN", BuildDDxBinary(t))

	cases := []struct {
		profile          string
		wantSeededCounts map[string]int
		wantFreshCounts  map[string]int
	}{
		{
			profile:          "minimal",
			wantSeededCounts: map[string]int{"": 0},
			wantFreshCounts:  map[string]int{"": 0},
		},
		{
			profile:          "standard",
			wantSeededCounts: map[string]int{"": 5},
			wantFreshCounts:  map[string]int{"": 5},
		},
		{
			profile: "multi-project",
			wantSeededCounts: map[string]int{
				"proj-a": 5,
				"proj-b": 0,
			},
			wantFreshCounts: map[string]int{
				"proj-a": 5,
				"proj-b": 0,
			},
		},
		{
			profile: "federated",
			wantSeededCounts: map[string]int{
				"hub":   5,
				"spoke": 0,
			},
			wantFreshCounts: map[string]int{
				"hub":   5,
				"spoke": 0,
			},
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.profile, func(t *testing.T) {
			resetFixtureRepoCacheForTest()

			originalBuild := fixtureRepoBuildFunc
			var (
				mu    sync.Mutex
				counts = map[string]int{}
			)
			fixtureRepoBuildFunc = func(repoRoot, dest, profile, bin string) error {
				mu.Lock()
				counts[profile]++
				mu.Unlock()
				return originalBuild(repoRoot, dest, profile, bin)
			}
			t.Cleanup(func() {
				fixtureRepoBuildFunc = originalBuild
				resetFixtureRepoCacheForTest()
			})

			first := NewFixtureRepo(t, tc.profile)
			second := NewFixtureRepo(t, tc.profile)

			if first == second {
				t.Fatalf("two fixture repos for profile %q resolved to the same path %q", tc.profile, first)
			}

			mu.Lock()
			gotBuilds := counts[tc.profile]
			mu.Unlock()
			if gotBuilds != 1 {
				t.Fatalf("build-fixture-repo.sh invocations for %q = %d, want 1", tc.profile, gotBuilds)
			}

			assertFixtureProfileLayout(t, first, tc.profile, tc.wantSeededCounts)
			assertFixtureProfileLayout(t, second, tc.profile, tc.wantFreshCounts)

			marker := filepath.Join(first, "isolation-marker.txt")
			if err := os.WriteFile(marker, []byte("first repo only"), 0o644); err != nil {
				t.Fatalf("write marker into first fixture repo: %v", err)
			}
			if _, err := os.Stat(filepath.Join(second, "isolation-marker.txt")); !os.IsNotExist(err) {
				t.Fatalf("marker file unexpectedly visible in second fixture repo: %v", err)
			}
		})
	}
}

func resetFixtureRepoCacheForTest() {
	fixtureRepoCacheMu.Lock()
	defer fixtureRepoCacheMu.Unlock()

	fixtureRepoCacheEntries = map[string]*fixtureRepoCacheEntry{}
	fixtureRepoCacheRootOnce = sync.Once{}
	fixtureRepoCacheRootPath = ""
	fixtureRepoCacheRootErr = nil
}

func assertFixtureProfileLayout(t *testing.T, root, profile string, wantCounts map[string]int) {
	t.Helper()

	switch profile {
	case "minimal", "standard":
		assertBeadCount(t, filepath.Join(root, ".ddx", "beads.jsonl"), wantCounts[""])
	case "multi-project":
		assertBeadCount(t, filepath.Join(root, "proj-a", ".ddx", "beads.jsonl"), wantCounts["proj-a"])
		assertBeadCount(t, filepath.Join(root, "proj-b", ".ddx", "beads.jsonl"), wantCounts["proj-b"])
	case "federated":
		assertBeadCount(t, filepath.Join(root, "hub", ".ddx", "beads.jsonl"), wantCounts["hub"])
		assertBeadCount(t, filepath.Join(root, "spoke", ".ddx", "beads.jsonl"), wantCounts["spoke"])
	default:
		t.Fatalf("unexpected profile %q", profile)
	}
}

func assertBeadCount(t *testing.T, path string, want int) {
	t.Helper()

	f, err := os.Open(path)
	if err != nil {
		t.Fatalf("open %s: %v", path, err)
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	got := 0
	for scanner.Scan() {
		got++
	}
	if err := scanner.Err(); err != nil {
		t.Fatalf("scan %s: %v", path, err)
	}
	if got != want {
		t.Fatalf("%s line count = %d, want %d", path, got, want)
	}
}

func TestCopyFixtureRepoTreeKeepsIsolatedCopies(t *testing.T) {
	t.Setenv("DDX_BIN", BuildDDxBinary(t))
	resetFixtureRepoCacheForTest()

	originalBuild := fixtureRepoBuildFunc
	var builds int
	fixtureRepoBuildFunc = func(repoRoot, dest, profile, bin string) error {
		builds++
		return originalBuild(repoRoot, dest, profile, bin)
	}
	t.Cleanup(func() {
		fixtureRepoBuildFunc = originalBuild
		resetFixtureRepoCacheForTest()
	})

	first := NewFixtureRepo(t, "standard")
	second := NewFixtureRepo(t, "standard")
	if builds != 1 {
		t.Fatalf("build-fixture-repo.sh invocations for standard = %d, want 1", builds)
	}

	marker := filepath.Join(first, "first-only.txt")
	if err := os.WriteFile(marker, []byte("only in first copy"), 0o644); err != nil {
		t.Fatalf("write marker into first copy: %v", err)
	}

	if _, err := os.Stat(filepath.Join(second, "first-only.txt")); !os.IsNotExist(err) {
		t.Fatalf("first-only marker unexpectedly visible in second copy: %v", err)
	}
}

// Package testutils provides shared helpers for tests and acceptance demos
// that need a clean ddx-initialized git repo without polluting the main DDx
// project. The canonical entry point is NewFixtureRepo, which wraps
// scripts/build-fixture-repo.sh and auto-cleans via t.Cleanup.
package testutils

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"sync"
	"testing"
)

// fixtureRepoBaseName is the leaf directory name given to every fixture
// project. It must satisfy the bead-identifier charset (^[a-zA-Z0-9-]+$,
// see internal/bead/id.go), because the bead prefix is derived from the git
// root's basename — a t.TempDir() leaf such as "001" would be numeric-only but
// the surrounding test-name path can contain characters (e.g. "_") that are
// rejected by `ddx bead create`. Nesting a fixed safe name under t.TempDir()
// guarantees a valid prefix regardless of the test name.
const fixtureRepoBaseName = "ddxfixture"

// NewFixtureRepo builds a clean ddx-initialized git repo for the given profile
// (minimal, standard, multi-project, federated) and returns its path. The repo
// is created under t.TempDir() so it is removed automatically when the test
// finishes (the auto-clean promised in scripts/build-fixture-repo.md).
//
// For minimal/standard the returned path is the project root; for
// multi-project/federated it is the parent dir whose sub-projects live
// underneath (proj-a, proj-b / hub, spoke).
//
// The ddx binary used for seeding is resolved via DDxBinary. Global and system
// git config are neutralized for the seeding subprocess so a developer box's
// commit.gpgsign (which points at a host-specific signer) does not break the
// fixture's own commits; repo-local commit.gpgsign is additionally disabled on
// each created project so subsequent ddx commits in the test never attempt to
// sign.
func NewFixtureRepo(t *testing.T, profile string) string {
	t.Helper()

	bin := DDxBinary(t)
	root := repoRoot(t)
	dest := filepath.Join(t.TempDir(), fixtureRepoBaseName)
	cached := cachedFixtureRepo(t, root, profile, bin)
	copyFixtureRepoTree(t, cached, dest)

	return dest
}

// fixtureProjectDirs returns the per-project git roots created for a profile,
// so repo-local config can be applied to each.
func fixtureProjectDirs(dest, profile string) []string {
	switch profile {
	case "multi-project":
		return []string{filepath.Join(dest, "proj-a"), filepath.Join(dest, "proj-b")}
	case "federated":
		return []string{filepath.Join(dest, "hub"), filepath.Join(dest, "spoke")}
	default:
		return []string{dest}
	}
}

type fixtureRepoCacheEntry struct {
	once sync.Once
	path string
	err  error
}

var (
	builtBinaryOnce sync.Once
	builtBinaryPath string
	builtBinaryErr  error

	fixtureRepoCacheMu       sync.Mutex
	fixtureRepoCacheRootOnce sync.Once
	fixtureRepoCacheRootPath string
	fixtureRepoCacheRootErr  error
	fixtureRepoCacheEntries  = map[string]*fixtureRepoCacheEntry{}

	fixtureRepoBuildFunc = buildFixtureRepoCache
)

// DDxBinary resolves a ddx binary for fixture seeding and subprocess tests. It
// prefers $DDX_BIN, then `ddx` on PATH, and otherwise lazily builds one from
// cli/ once per process. The built binary lives in an os.MkdirTemp dir that
// outlives any single test so concurrent fixtures can share it.
func DDxBinary(t *testing.T) string {
	t.Helper()
	if env := os.Getenv("DDX_BIN"); env != "" {
		if _, err := os.Stat(env); err == nil {
			return env
		}
	}
	if p, err := exec.LookPath("ddx"); err == nil {
		return p
	}
	return BuildDDxBinary(t)
}

// BuildDDxBinary builds the ddx binary from the current cli/ source tree once
// per process and returns its path. Tests that must exercise the current source
// (rather than a possibly-stale `ddx` on PATH) should build with this and pin it
// via t.Setenv("DDX_BIN", ...) so NewFixtureRepo seeds with the same binary. The
// binary lives in an os.MkdirTemp dir that outlives any single test.
func BuildDDxBinary(t *testing.T) string {
	t.Helper()
	builtBinaryOnce.Do(func() {
		dir, err := os.MkdirTemp("", "ddx-fixture-bin-*")
		if err != nil {
			builtBinaryErr = err
			return
		}
		out := filepath.Join(dir, "ddx")
		build := exec.Command("go", "build", "-buildvcs=false", "-o", out, ".")
		build.Dir = cliDir(t)
		if combined, err := build.CombinedOutput(); err != nil {
			builtBinaryErr = err
			t.Logf("go build ddx from source failed:\n%s", combined)
			return
		}
		builtBinaryPath = out
	})
	if builtBinaryErr != nil {
		t.Fatalf("build ddx binary from source: %v", builtBinaryErr)
	}
	return builtBinaryPath
}

// cliDir walks up from the test's working directory to the directory that
// holds go.mod (the cli/ module root).
func cliDir(t *testing.T) string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	dir := wd
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			t.Fatalf("could not locate go.mod (cli module root) from %s", wd)
		}
		dir = parent
	}
}

// repoRoot returns the repository root (parent of the cli/ module dir), where
// scripts/ lives.
func repoRoot(t *testing.T) string {
	t.Helper()
	return filepath.Dir(cliDir(t))
}

func cachedFixtureRepo(t *testing.T, root, profile, bin string) string {
	t.Helper()

	entry := fixtureRepoCacheEntryFor(profile)
	entry.once.Do(func() {
		cacheRoot, err := fixtureRepoCacheRoot()
		if err != nil {
			entry.err = err
			return
		}
		entry.path = filepath.Join(cacheRoot, profile)
		entry.err = fixtureRepoBuildFunc(root, entry.path, profile, bin)
	})
	if entry.err != nil {
		t.Fatalf("build fixture repo cache (profile=%s): %v", profile, entry.err)
	}
	return entry.path
}

func fixtureRepoCacheEntryFor(profile string) *fixtureRepoCacheEntry {
	fixtureRepoCacheMu.Lock()
	defer fixtureRepoCacheMu.Unlock()

	if entry, ok := fixtureRepoCacheEntries[profile]; ok {
		return entry
	}
	entry := &fixtureRepoCacheEntry{}
	fixtureRepoCacheEntries[profile] = entry
	return entry
}

func fixtureRepoCacheRoot() (string, error) {
	fixtureRepoCacheRootOnce.Do(func() {
		fixtureRepoCacheRootPath, fixtureRepoCacheRootErr = os.MkdirTemp("", "ddx-fixture-cache-*")
	})
	return fixtureRepoCacheRootPath, fixtureRepoCacheRootErr
}

func buildFixtureRepoCache(repoRoot, dest, profile, bin string) error {
	script := filepath.Join(repoRoot, "scripts", "build-fixture-repo.sh")

	emptyGlobalCfg, err := os.MkdirTemp("", "ddx-fixture-gitconfig-*")
	if err != nil {
		return err
	}
	emptyGlobalCfg = filepath.Join(emptyGlobalCfg, "gitconfig-global")
	if err := os.WriteFile(emptyGlobalCfg, nil, 0o644); err != nil {
		return err
	}

	cmd := exec.Command("bash", script, dest, "--profile", profile)
	cmd.Env = append(os.Environ(),
		"DDX_BIN="+bin,
		"GIT_CONFIG_GLOBAL="+emptyGlobalCfg,
		"GIT_CONFIG_SYSTEM=/dev/null",
	)
	if out, err := cmd.CombinedOutput(); err != nil {
		return fmt.Errorf("build-fixture-repo.sh failed (profile=%s): %w\n%s", profile, err, out)
	}

	for _, dir := range fixtureProjectDirs(dest, profile) {
		gc := exec.Command("git", "-C", dir, "config", "commit.gpgsign", "false")
		gc.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
		if out, err := gc.CombinedOutput(); err != nil {
			return fmt.Errorf("disable commit.gpgsign in %s: %w\n%s", dir, err, out)
		}
	}

	return nil
}

func copyFixtureRepoTree(t *testing.T, src, dest string) {
	t.Helper()

	if err := os.RemoveAll(dest); err != nil {
		t.Fatalf("clear fixture repo destination: %v", err)
	}
	if err := copyDirectory(src, dest); err != nil {
		t.Fatalf("copy fixture repo tree: %v", err)
	}
}

func copyDirectory(src, dest string) error {
	if err := os.MkdirAll(dest, 0o755); err != nil {
		return err
	}
	entries, err := os.ReadDir(src)
	if err != nil {
		return err
	}
	for _, entry := range entries {
		srcPath := filepath.Join(src, entry.Name())
		destPath := filepath.Join(dest, entry.Name())
		if entry.IsDir() {
			if err := copyDirectory(srcPath, destPath); err != nil {
				return err
			}
			continue
		}
		info, err := entry.Info()
		if err != nil {
			return err
		}
		data, err := os.ReadFile(srcPath)
		if err != nil {
			return err
		}
		if err := os.WriteFile(destPath, data, info.Mode().Perm()); err != nil {
			return err
		}
		if err := os.Chmod(destPath, info.Mode()); err != nil {
			return err
		}
	}
	return nil
}

