 94				if err := os.WriteFile(marker, []byte("first repo only"), 0o644); err != nil {
 95					t.Fatalf("write marker into first fixture repo: %v", err)
 96				}
 97				if _, err := os.Stat(filepath.Join(second, "isolation-marker.txt")); !os.IsNotExist(err) {
 98					t.Fatalf("marker file unexpectedly visible in second fixture repo: %v", err)
 99				}
100			})
101		}
102	}
