114	func assertFixtureProfileLayout(t *testing.T, root, profile string, wantCounts map[string]int) {
115		t.Helper()
116	
117		switch profile {
118		case "minimal", "standard":
119			assertBeadCount(t, filepath.Join(root, ddxroot.DirName, "beads.jsonl"), wantCounts[""])
120		case "multi-project":
121			assertBeadCount(t, filepath.Join(root, "proj-a", ddxroot.DirName, "beads.jsonl"), wantCounts["proj-a"])
122			assertBeadCount(t, filepath.Join(root, "proj-b", ddxroot.DirName, "beads.jsonl"), wantCounts["proj-b"])
123		case "federated":
124			assertBeadCount(t, filepath.Join(root, "hub", ddxroot.DirName, "beads.jsonl"), wantCounts["hub"])
125			assertBeadCount(t, filepath.Join(root, "spoke", ddxroot.DirName, "beads.jsonl"), wantCounts["spoke"])
126		default:
127			t.Fatalf("unexpected profile %q", profile)
128		}
129	}
