131	func assertBeadCount(t *testing.T, path string, want int) {
132		t.Helper()
133	
134		f, err := os.Open(path)
135		if err != nil {
136			t.Fatalf("open %s: %v", path, err)
137		}
138		defer f.Close()
139	
140		scanner := bufio.NewScanner(f)
141		got := 0
142		for scanner.Scan() {
143			got++
144		}
145		if err := scanner.Err(); err != nil {
146			t.Fatalf("scan %s: %v", path, err)
147		}
148		if got != want {
149			t.Fatalf("%s line count = %d, want %d", path, got, want)
150		}
151	}
