154		t.Setenv("DDX_BIN", BuildDDxBinary(t))
155		resetFixtureRepoCacheForTest()
156	
157		originalBuild := fixtureRepoBuildFunc
158		var builds int
159		fixtureRepoBuildFunc = func(repoRoot, dest, profile, bin string) error {
160			builds++
161			return originalBuild(repoRoot, dest, profile, bin)
162		}
163		t.Cleanup(func() {
164			fixtureRepoBuildFunc = originalBuild
165			resetFixtureRepoCacheForTest()
166		})
167	
168		first := NewFixtureRepo(t, "standard")
169		second := NewFixtureRepo(t, "standard")
170		if builds != 1 {
171			t.Fatalf("build-fixture-repo.sh invocations for standard = %d, want 1", builds)
172		}
173	
174		marker := filepath.Join(first, "first-only.txt")
175		if err := os.WriteFile(marker, []byte("only in first copy"), 0o644); err != nil {
176			t.Fatalf("write marker into first copy: %v", err)
177		}
178	
179		if _, err := os.Stat(filepath.Join(second, "first-only.txt")); !os.IsNotExist(err) {
180			t.Fatalf("first-only marker unexpectedly visible in second copy: %v", err)
181		}
